import React, { useEffect } from 'react';
import type { BadgeDefinition } from '../../config/badges';

interface Props {
  badge: BadgeDefinition;
  onDismiss: () => void;
}

export default function AchievementToast({ badge, onDismiss }: Props) {
  useEffect(() => {
    const timer = setTimeout(onDismiss, 5000);
    return () => clearTimeout(timer);
  }, [onDismiss]);

  return (
    <div
      onClick={onDismiss}
      style={{
        position: 'fixed',
        top: '1.5rem',
        right: '1.5rem',
        zIndex: 10001,
        background: 'var(--panel-bg, #1a1f2e)',
        border: `1px dashed ${badge.color}60`,
        borderRadius: 'var(--brutal-radius, 4px)',
        boxShadow: `2px 2px 0px ${badge.color}40`,
        padding: '1rem 1.5rem',
        display: 'flex',
        alignItems: 'center',
        gap: '1rem',
        cursor: 'pointer',
        animation: 'slideInRight 0.4s ease',
        maxWidth: '340px',
      }}
    >
      <div style={{
        width: '48px',
        height: '48px',
        borderRadius: 'var(--brutal-radius, 4px)',
        background: `${badge.color}20`,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        flexShrink: 0,
      }}>
        <i className={`fa-solid ${badge.icon}`} style={{ fontSize: '1.3rem', color: badge.color }} />
      </div>
      <div>
        <div style={{ fontSize: '0.65rem', color: badge.color, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.15rem' }}>
          Badge Earned
        </div>
        <div style={{ fontSize: '0.95rem', fontWeight: 700, color: 'var(--text-primary)' }}>
          {badge.name}
        </div>
        <div style={{ fontSize: '0.78rem', color: 'var(--text-secondary)' }}>
          {badge.description}
        </div>
      </div>
    </div>
  );
}
