import React from 'react';
import { BADGE_LIST } from '../config/badges';
import type { Achievement } from '../hooks/useAchievements';

interface Props {
  achievements: Achievement[];
}

export default function BadgeShowcase({ achievements }: Props) {
  const earnedIds = new Set(achievements.map(a => a.badge_id));

  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))', gap: '0.75rem' }}>
      {BADGE_LIST.map(badge => {
        const earned = earnedIds.has(badge.id);
        const achievement = achievements.find(a => a.badge_id === badge.id);

        return (
          <div
            key={badge.id}
            className="glass-panel"
            style={{
              padding: '1rem',
              textAlign: 'center',
              opacity: earned ? 1 : 0.4,
              transition: 'opacity 0.2s',
            }}
          >
            <div style={{
              width: '40px',
              height: '40px',
              borderRadius: 'var(--brutal-radius, 4px)',
              background: earned ? `${badge.color}20` : 'rgba(255,255,255,0.05)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              margin: '0 auto 0.5rem',
            }}>
              <i
                className={`fa-solid ${earned ? badge.icon : 'fa-lock'}`}
                style={{
                  fontSize: '1.1rem',
                  color: earned ? badge.color : 'var(--text-secondary)',
                }}
              />
            </div>
            <div style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-primary)', marginBottom: '0.15rem' }}>
              {badge.name}
            </div>
            <div style={{ fontSize: '0.65rem', color: 'var(--text-secondary)', lineHeight: 1.3 }}>
              {earned && achievement
                ? new Date(achievement.earned_at).toLocaleDateString()
                : badge.description}
            </div>
          </div>
        );
      })}
    </div>
  );
}
